class MyCircularDeque {
    private java.util.Deque<Integer> deque = new java.util.ArrayDeque<>();
    private int capacity;

    public MyCircularDeque(int k) {
        capacity = k;
    }

    public boolean insertFront(int value) {
        if (deque.size() == capacity) return false;
        deque.addFirst(value);
        return true;
    }

    public boolean insertLast(int value) {
        if (deque.size() == capacity) return false;
        deque.addLast(value);
        return true;
    }

    public boolean deleteFront() {
        if (deque.isEmpty()) return false;
        deque.removeFirst();
        return true;
    }

    public boolean deleteLast() {
        if (deque.isEmpty()) return false;
        deque.removeLast();
        return true;
    }

    public int getFront() {
        return deque.isEmpty() ? -1 : deque.peekFirst();
    }

    public int getRear() {
        return deque.isEmpty() ? -1 : deque.peekLast();
    }

    public boolean isEmpty() {
        return deque.isEmpty();
    }

    public boolean isFull() {
        return deque.size() == capacity;
    }
}

class MyCircularDeque {
    private int[] arr;
    private int front, size, capacity;

    public MyCircularDeque(int k) {
        arr = new int[k];
        capacity = k;
        front = 0;
        size = 0;
    }

    public boolean insertFront(int value) {
        if (size == capacity) return false;
        front = (front - 1 + capacity) % capacity;
        arr[front] = value;
        size++;
        return true;
    }

    public boolean insertLast(int value) {
        if (size == capacity) return false;
        int rear = (front + size) % capacity;
        arr[rear] = value;
        size++;
        return true;
    }

    public boolean deleteFront() {
        if (size == 0) return false;
        front = (front + 1) % capacity;
        size--;
        return true;
    }

    public boolean deleteLast() {
        if (size == 0) return false;
        size--;
        return true;
    }

    public int getFront() {
        return size == 0 ? -1 : arr[front];
    }

    public int getRear() {
        return size == 0 ? -1 : arr[(front + size - 1) % capacity];
    }

    public boolean isEmpty() {
        return size == 0;
    }

    public boolean isFull() {
        return size == capacity;
    }
}

